  4→function pickFreePort() {
  5→	return execFileSync(
  6→		process.execPath,
  7→		[
  8→			"-e",
  9→			"const net=require('net');const s=net.createServer();s.listen(0,'127.0.0.1',()=>{process.stdout.write(String(s.address().port));s.close();});",
 10→		],
 11→		{ encoding: "utf8" },
 12→	).trim();
 13→}
