 15→function resolvePort(envVar, usedPortSet) {
 16→	var configured = process.env[envVar];
 17→	if (configured && configured !== "0") {
 18→		usedPortSet.add(configured);
 19→		return configured;
 20→	}
 21→	var picked = pickFreePort();
 22→	while (usedPortSet.has(picked)) {
 23→		picked = pickFreePort();
 24→	}
 25→	process.env[envVar] = picked;
 26→	usedPortSet.add(picked);
 27→	return picked;
 28→}
