  1→const { expect, test } = require("../base-test");
  2→const { navigateAndWait, openChatMoreModal, waitForWsConnected, watchPageErrors } = require("../helpers");
  3→
  4→function isRetryableRpcError(message) {
  5→	if (typeof message !== "string") return false;
  6→	return message.includes("WebSocket not connected") || message.includes("WebSocket disconnected");
  7→}
  8→
  9→function isNoProvidersConfiguredResponse(response) {
 10→	// `localizeRpcError` in helpers.js replaces `error.message` with a locale
 11→	// string (e.g. "An internal server error occurred.") and moves the original
 12→	// backend message to `serverMessage`. Check both so the test still skips
 13→	// when providers are unconfigured.
 14→	const err = response?.error;
 15→	const message = err?.serverMessage || err?.message || "";
 16→	return (
 17→		err?.code === "UNAVAILABLE" ||
 18→		message.includes("no LLM providers configured") ||
 19→		message.includes("chat not configured")
 20→	);
 21→}
 22→
 23→function ignoreWaitError() {
 24→	return "ignored";
 25→}
 26→
 27→async function sendRpcFromPage(page, method, params) {
 28→	let lastResponse = null;
 29→	for (let attempt = 0; attempt < 30; attempt++) {
 30→		if (attempt > 0) {
 31→			await waitForWsConnected(page, 5_000).catch(ignoreWaitError);
 32→		}
 33→		lastResponse = await page
 34→			.evaluate(
 35→				async ({ methodName, methodParams }) => {
 36→					var appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
 37→					if (!appScript) throw new Error("app module script not found");
 38→					var appUrl = new URL(appScript.src, window.location.origin);
 39→					var prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
 40→					var helpers = await import(`${prefix}js/helpers.js`);
 41→					return helpers.sendRpc(methodName, methodParams);
 42→				},
 43→				{
 44→					methodName: method,
 45→					methodParams: params,
 46→				},
 47→			)
 48→			.catch((error) => ({ ok: false, error: { message: error?.message || String(error) } }));
 49→
 50→		if (lastResponse?.ok) return lastResponse;
 51→		if (!isRetryableRpcError(lastResponse?.error?.message)) return lastResponse;
 52→	}
 53→	return lastResponse;
 54→}
 55→
 56→async function waitForWsConnectedIfPossible(page) {
 57→	await waitForWsConnected(page, 5_000).catch(ignoreWaitError);
 58→}
 59→
 60→async function mockFullContextRpc(page) {
 61→	await page.evaluate(async () => {
 62→		var appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
 63→		if (!appScript) throw new Error("app module script not found");
 64→		var appUrl = new URL(appScript.src, window.location.origin);
 65→		var prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
 66→		var stateModule = await import(`${prefix}js/state.js`);
 67→		var ws = stateModule.ws;
 68→		if (!ws) throw new Error("websocket unavailable");
 69→
 70→		if (!window.__origFullContextWsSend) {
 71→			window.__origFullContextWsSend = ws.send.bind(ws);
 72→		}
 73→		window.__mockPromptMemoryRefreshCount = 0;
 74→		window.__mockPromptMemoryVersion = 1;
 75→
 76→		function mockPromptMemory() {
 77→			return {
 78→				mode: "frozen-at-session-start",
 79→				snapshotActive: true,
 80→				present: true,
 81→				chars: window.__mockPromptMemoryVersion === 1 ? 12 : 24,
 82→				path: window.__mockPromptMemoryVersion === 1 ? "/tmp/MEMORY-v1.md" : "/tmp/MEMORY-v2.md",
 83→				fileSource: "root_workspace",
 84→			};
 85→		}
 86→
 87→		function resolvePending(id, payload) {
 88→			var resolver = stateModule.pending?.[id];
 89→			if (typeof resolver !== "function") return false;
 90→			delete stateModule.pending[id];
 91→			resolver({ ok: true, payload });
 92→			return true;
 93→		}
 94→
 95→		function handleMockPromptMemoryRpc(parsed) {
 96→			if (parsed?.method === "chat.context") {
 97→				return resolvePending(parsed.id, {
 98→					session: { key: "main", messageCount: 2, model: "demo-model" },
 99→					supportsTools: true,
100→					promptMemory: mockPromptMemory(),
101→				});
102→			}
103→			if (parsed?.method === "chat.full_context") {
104→				return resolvePending(parsed.id, {
105→					messageCount: 2,
106→					systemPromptChars: 42,
107→					totalChars: 128,
108→					promptMemory: mockPromptMemory(),
109→					messages: [
110→						{ role: "user", content: "How are you?" },
111→						{
112→							role: "assistant",
113→							content: "Doing fine.",
114→							tool_calls: [{ function: { name: "demo_tool", arguments: '{"hello":"world"}' } }],
115→						},
116→					],
117→					llmOutputs: [{ text: "assistant raw output" }],
118→				});
119→			}
120→			if (parsed?.method === "chat.prompt_memory.refresh") {
121→				window.__mockPromptMemoryRefreshCount += 1;
122→				window.__mockPromptMemoryVersion = 2;
123→				return resolvePending(parsed.id, {
124→					ok: true,
125→					sessionKey: "main",
126→					agentId: "main",
127→					snapshotCleared: true,
128→					promptMemory: mockPromptMemory(),
129→				});
130→			}
131→			return false;
132→		}
133→
134→		ws.send = (payload) => {
135→			try {
136→				var parsed = JSON.parse(payload);
137→				if (handleMockPromptMemoryRpc(parsed)) {
138→					return;
139→				}
140→			} catch (_err) {
141→				// Fall through to the original sender.
142→			}
143→			return window.__origFullContextWsSend(payload);
144→		};
145→	});
146→}
