198→async function openFullContextWithRetry(page) {
199→	const chatMoreModal = page.locator("#chatMoreModal");
200→	const fullContextModal = page.locator("#fullContextModal");
201→	const toggleBtn = page.locator("#fullContextBtn");
202→	const panel = page.locator("#fullContextPanel");
203→	const copyBtn = panel.getByRole("button", { name: "Copy", exact: true });
204→	const copiedBtn = panel.getByRole("button", { name: "Copied!", exact: true });
205→	const downloadBtn = panel.getByRole("button", { name: "Download", exact: true });
206→	const llmOutputBtn = panel.getByRole("button", { name: "LLM output", exact: true });
207→	const failedMsg = panel.getByText("Failed to build context", { exact: true });
208→
209→	for (let attempt = 0; attempt < 5; attempt++) {
210→		await waitForWsConnectedIfPossible(page);
211→		await closeFullContextIfOpen(page, fullContextModal);
212→
213→		await openChatMoreModal(page);
214→		await expect(toggleBtn).toBeVisible({ timeout: 8_000 });
215→		await toggleBtn.click();
216→		await expect(chatMoreModal).toBeHidden({ timeout: 8_000 });
217→		await expect(fullContextModal).toBeVisible({ timeout: 8_000 });
218→		await expect(panel).toBeVisible();
219→
220→		const result = await expect
221→			.poll(async () => await fullContextPanelState(copyBtn, copiedBtn, downloadBtn, llmOutputBtn, failedMsg), {
222→				timeout: 12_000,
223→			})
224→			.toBe("controls")
225→			.then(() => "controls")
226→			.catch(() => "failed");
227→
228→		if (result === "controls") {
229→			if (await copyBtn.isVisible().catch(() => false)) return copyBtn;
230→			if (await copiedBtn.isVisible().catch(() => false)) return copiedBtn;
231→			return copyBtn;
232→		}
233→		if (result === "failed") {
234→			const fullContextRpc = await sendRpcFromPage(page, "chat.full_context", {});
235→			if (isNoProvidersConfiguredResponse(fullContextRpc)) {
236→				return null;
237→			}
238→		}
239→	}
240→
241→	return false;
242→}
