 39→async function expectRpcOk(page, method, params) {
 40→	const response = await sendRpcFromPage(page, method, params);
 41→	expect(response?.ok, `RPC ${method} failed: ${response?.error?.message || "unknown error"}`).toBeTruthy();
 42→	return response;
 43→}
