 69→async function setSwitchRpcSendMode(page, mode, delayMs = 0) {
 70→	await page.evaluate(
 71→		async ({ desiredMode, desiredDelayMs }) => {
 72→			const appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
 73→			if (!appScript) throw new Error("app module script not found");
 74→			const appUrl = new URL(appScript.src, window.location.origin);
 75→			const prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
 76→			const stateModule = await import(`${prefix}js/state.js`);
 77→			const ws = stateModule.ws;
 78→			if (!ws) throw new Error("websocket unavailable");
 79→
 80→			if (!window.__origSwitchWsSend) {
 81→				window.__origSwitchWsSend = ws.send.bind(ws);
 82→			}
 83→			if (desiredMode === "restore") {
