 35→impl LiveChatService {
 36→    #[tracing::instrument(skip(self, params), fields(session_id))]
 37→    pub(super) async fn send_impl(&self, mut params: Value) -> ServiceResult {
 38→        // Support both text-only and multimodal content.
 39→        // - "text": string → plain text message
 40→        // - "content": array → multimodal content (text + images)
 41→        //
 42→        // Note: `text` and `message_content` are `mut` because a
 43→        // `MessageReceived` hook may return `ModifyPayload` to rewrite the
 44→        // inbound message before the turn begins (see GH #639).
 45→        let (mut text, mut message_content) = if let Some(content) = params.get("content") {
 46→            // Multimodal content - extract text for logging/hooks, parse into typed blocks
 47→            let text_part = content
 48→                .as_array()
 49→                .and_then(|arr| {
 50→                    arr.iter()
 51→                        .find(|block| block.get("type").and_then(|t| t.as_str()) == Some("text"))
 52→                        .and_then(|block| block.get("text").and_then(|t| t.as_str()))
 53→                })
 54→                .unwrap_or("[Image]")
 55→                .to_string();
 56→
 57→            // Parse JSON blocks into typed ContentBlock structs
 58→            let blocks: Vec<ContentBlock> = content
 59→                .as_array()
 60→                .map(|arr| {
 61→                    arr.iter()
 62→                        .filter_map(|block| {
 63→                            let block_type = block.get("type")?.as_str()?;
 64→                            match block_type {
 65→                                "text" => {
 66→                                    let text = block.get("text")?.as_str()?.to_string();
 67→                                    Some(ContentBlock::text(text))
 68→                                },
 69→                                "image_url" => {
