  1→//! GraphQL subscription resolvers.
  2→//!
  3→//! Subscriptions bridge from the gateway's broadcast channel. Each subscription
  4→//! filters events by name and deserializes the payload into typed events.
  5→
  6→use std::sync::Arc;
  7→
  8→use {
  9→    async_graphql::{Context, Result, Subscription},
 10→    tokio_stream::Stream,
 11→};
 12→
 13→use crate::{
 14→    context::GqlContext,
 15→    types::{GenericEvent, TickEvent},
 16→};
 17→
 18→/// Root subscription type.
 19→#[derive(Default)]
 20→pub struct SubscriptionRoot;
 21→
 22→#[Subscription]
 23→impl SubscriptionRoot {
 24→    /// Chat events (streaming tokens, completion, abort).
 25→    async fn chat_event(
 26→        &self,
 27→        ctx: &Context<'_>,
 28→        session_key: String,
 29→    ) -> Result<impl Stream<Item = GenericEvent>> {
 30→        let c = ctx.data::<Arc<GqlContext>>()?;
 31→        let mut rx = c.subscribe();
 32→        Ok(async_stream::stream! {
 33→            while let Ok((event_name, payload)) = rx.recv().await {
 34→                if event_name == "chat" {
 35→                    match payload.get("sessionKey").and_then(|v| v.as_str()) {
 36→                        Some(event_sk) if event_sk != session_key => continue,
 37→                        None => continue,
 38→                        _ => {}
 39→                    }
 40→                    yield GenericEvent::from(payload);
 41→                }
 42→            }
 43→        })
 44→    }
 45→
 46→    /// Session change events (patch, switch, delete).
 47→    async fn session_changed(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
 48→        event_stream(ctx, "session").await
 49→    }
 50→
 51→    /// Cron job notifications (created, updated, removed, run complete).
 52→    async fn cron_notification(
 53→        &self,
 54→        ctx: &Context<'_>,
 55→    ) -> Result<impl Stream<Item = GenericEvent>> {
 56→        event_stream(ctx, "cron").await
 57→    }
 58→
 59→    /// Channel events.
 60→    async fn channel_event(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
 61→        event_stream(ctx, "channel").await
 62→    }
 63→
 64→    /// Node connect/disconnect events.
 65→    async fn node_event(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = GenericEvent>> {
 66→        event_stream(ctx, "node").await
 67→    }
 68→
 69→    /// System tick events (periodic heartbeat with stats).
 70→    async fn tick(&self, ctx: &Context<'_>) -> Result<impl Stream<Item = TickEvent>> {
 71→        let c = ctx.data::<Arc<GqlContext>>()?;
 72→        let mut rx = c.subscribe();
 73→        Ok(async_stream::stream! {
 74→            while let Ok((name, payload)) = rx.recv().await {
 75→                if name == "tick"
 76→                    && let Ok(evt) = serde_json::from_value::<TickEvent>(payload)
 77→                {
 78→                    yield evt;
 79→                }
 80→            }
 81→        })
 82→    }
