 31→ * Returns an array that fills as errors occur.
 32→ *
 33→ * Usage:
 34→ *   const pageErrors = watchPageErrors(page);
 35→ *   // ... interact with page ...
 36→ *   expect(pageErrors).toEqual([]);
 37→ */
 38→function watchPageErrors(page) {
 39→	const pageErrors = [];
 40→	page.on("pageerror", (err) => pageErrors.push(err.message));
 41→	return pageErrors;
 42→}
