 44→/**
 45→ * Wait for the WebSocket connection status dot to reach "connected".
 46→ * Note: #statusText is intentionally set to "" when connected, so we
 47→ * only check the dot's CSS class.
 48→ */
 49→async function waitForWsConnected(page, timeoutMs = 20_000) {
 50→	await expect
 51→		.poll(
 52→			async () => {
 53→				const statusDotConnected = await page
 54→					.locator("#statusDot")
 55→					.getAttribute("class")
 56→					.then((cls) => /connected/.test(cls || ""))
 57→					.catch(() => false);
 58→				if (!statusDotConnected) return false;
 59→				return page
 60→					.evaluate(async () => {
 61→						const appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
 62→						if (!appScript) return false;
 63→						const appUrl = new URL(appScript.src, window.location.origin);
 64→						const prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
 65→						const state = await import(`${prefix}js/state.js`);
 66→						return Boolean(state.connected && state.ws && state.ws.readyState === WebSocket.OPEN);
 67→					})
 68→					.catch(() => false);
 69→			},
 70→			{ timeout: timeoutMs },
 71→		)
 72→		.toBe(true);
 73→}
