 84→/**
 85→ * Navigate to a path, wait for SPA content to mount, and assert no errors.
 86→ * Returns the pageErrors array for further assertions.
 87→ */
 88→async function navigateAndWait(page, path) {
 89→	const pageErrors = watchPageErrors(page);
 90→	let lastError = null;
 91→	for (let attempt = 0; attempt < 3; attempt++) {
 92→		try {
 93→			await page.goto(path, { waitUntil: "domcontentloaded" });
 94→			await expectPageContentMounted(page);
 95→			return pageErrors;
 96→		} catch (error) {
 97→			lastError = error;
 98→			if (!isRetryableNavigationError(error) || attempt === 2) {
 99→				break;
100→			}
101→		}
102→	}
103→	if (lastError) throw lastError;
104→	return pageErrors;
105→}
