126→		.poll(
127→			() =>
128→				page.evaluate(() => {
129→					return window.__moltis_stores?.sessionStore?.activeSessionKey?.value || "";
130→				}),
131→			{ timeout: timeoutMs },
132→		)
133→		.not.toBe(previousActiveKey);
134→
135→	await expect
136→		.poll(
137→			() =>
138→				page.evaluate(() => {
139→					const key = window.__moltis_stores?.sessionStore?.activeSessionKey?.value || "";
