 40→	return detectOnboardingStep(page);
 41→}
 42→
 43→async function advanceToIdentityStep(page) {
 44→	for (let i = 0; i < 6; i++) {
 45→		const step = await detectOnboardingStep(page);
 46→		if (step === "identity" || step === "chats" || step === "summary") return step;
 47→		if (step === "auth") {
 48→			await completePasswordAuthStep(page);
 49→			continue;
 50→		}
 51→		if (step === "providers" || step === "voice" || step === "remote-access" || step === "channel") {
 52→			if (await clickFirstVisibleButton(page, { name: /skip for now/i })) continue;
 53→			if (await clickFirstVisibleButton(page, { name: /continue/i })) continue;
 54→		}
 55→		break;
 56→	}
 57→	return detectOnboardingStep(page);
 58→}
 59→
 60→async function dismissRecoveryKeyIfShown(page) {
 61→	const recoveryHeading = page.getByText("Password set and vault initialized", { exact: true });
 62→	if (await isVisible(recoveryHeading)) {
 63→		// Verify key is displayed in a code block
 64→		const codeBlock = page.locator(".onboarding-card code");
 65→		await codeBlock.waitFor({ state: "visible", timeout: 3_000 }).catch(() => {});
 66→		// Verify copy button exists
 67→		const copyBtn = page.getByRole("button", { name: /^Copy/, exact: false });
 68→		if (await isVisible(copyBtn)) {
 69→			await copyBtn.click();
 70→		}
 71→		// Click Continue to proceed
 72→		if (await clickFirstVisibleButton(page, { name: /^Continue$/ })) return true;
 73→	}
 74→	return false;
 75→}
 76→
 77→async function completePasswordAuthStep(page) {
 78→	if (await clickFirstVisibleButton(page, { name: /^Next$/ })) return true;
 79→
 80→	const setupCodeInput = page.getByPlaceholder("6-digit code from terminal");
 81→	if (await isVisible(setupCodeInput)) {
 82→		await setupCodeInput.fill("123456");
 83→
 84→		const passwordCard = page.locator(".backend-card").filter({ hasText: "Password" }).first();
 85→		if (await isVisible(passwordCard)) {
 86→			await passwordCard.click({ timeout: 1_500 }).catch(() => {});
 87→		}
 88→	}
 89→
 90→	const inputs = page.locator(".onboarding-card input[type='password']");
 91→	if ((await inputs.count()) >= 2) {
 92→		await inputs.first().fill("testpassword1");
 93→		await inputs.nth(1).fill("testpassword1");
 94→
 95→		if (await clickFirstVisibleButton(page, { name: /^Set password(?: & continue)?$/ })) {
 96→			// After password setup, a recovery key interstitial may appear
 97→			await page.waitForTimeout(500);
 98→			await dismissRecoveryKeyIfShown(page);
 99→			return true;
100→		}

