1001→            .await
1002→        {
1003→            warn!("failed to persist user message: {e}");
1004→        }
1005→
1006→        // Set preview from the first user message if not already set.
1007→        if let Some(entry) = self.session_metadata.get(&session_key).await
1008→            && entry.preview.is_none()
1009→        {
1010→            let preview_text = extract_preview_from_value(&user_msg.to_value());
1011→            if let Some(preview) = preview_text {
1012→                self.session_metadata
1013→                    .set_preview(&session_key, Some(&preview))
1014→                    .await;
1015→            }
1016→        }
1017→
1018→        let agent_timeout_secs = moltis_config::discover_and_load().tools.agent_timeout_secs;
1019→
1020→        let message_queue = Arc::clone(&self.message_queue);
1021→        let state_for_drain = Arc::clone(&self.state);
1022→        let active_event_forwarders = Arc::clone(&self.active_event_forwarders);
1023→        let terminal_runs = Arc::clone(&self.terminal_runs);
1024→        let deferred_channel_target = deferred_channel_target.clone();
1025→
1026→        let handle = tokio::spawn(async move {
1027→            let permit = permit; // hold permit until agent run completes
1028→            let ctx_ref = project_context.as_deref();
1029→            if let Some(target) = deferred_channel_target {
1030→                // Register the channel reply target only after we own the
1031→                // session permit, so queued messages keep per-message routing.
1032→                state.push_channel_reply(&session_key_clone, target).await;
1033→            }
1034→            active_reply_medium
1035→                .write()
1036→                .await
1037→                .insert(session_key_clone.clone(), desired_reply_medium);
1038→            active_partial_assistant.write().await.insert(
1039→                session_key_clone.clone(),
1040→                ActiveAssistantDraft::new(&run_id_clone, &model_id, &provider_name, client_seq),
1041→            );
1042→            if desired_reply_medium == ReplyMedium::Voice {
1043→                broadcast(
1044→                    &state,
1045→                    "chat",
1046→                    serde_json::json!({
1047→                        "runId": run_id_clone,
1048→                        "sessionKey": session_key_clone,
1049→                        "state": "voice_pending",
1050→                    }),
1051→                    BroadcastOpts::default(),
1052→                )
1053→                .await;
1054→            }
1055→            let agent_fut = async {
1056→                if stream_only {
1057→                    run_streaming(
1058→                        persona,
1059→                        &state,
1060→                        &model_store,
