+// Tests for GH #729: User messages sent via the GraphQL/RPC API (not the web UI)
+// should appear in the web interface in real-time.
+//
+// Currently, when a message is sent via `chat.send` from an external client
+// (GraphQL mutation, mobile app, etc.), the backend persists it and runs the
+// LLM, but no WebSocket event is broadcast for the user message itself.  The
+// web UI only shows it after a full page reload or session switch.
+//
+// The fix will:
+//  1. Backend: broadcast a `user_message` event after persisting the user
+//     message in send_impl().
+//  2. Frontend: add a `user_message` handler in websocket.js that renders the
+//     message and caches it, similar to the existing `channel_user` handler.
+//  3. Frontend: skip rendering when the current connection originated the
+//     message (the web UI already renders it optimistically).
+
+const { expect, test } = require("../base-test");
+const { navigateAndWait, waitForWsConnected, watchPageErrors } = require("../helpers");
+
+function isRetryableRpcError(message) {
+	if (typeof message !== "string") return false;
+	return message.includes("WebSocket not connected") || message.includes("WebSocket disconnected");
+}
+
+async function sendRpcFromPage(page, method, params) {
+	let lastResponse = null;
+	for (let attempt = 0; attempt < 40; attempt++) {
+		if (attempt > 0) {
+			await waitForWsConnected(page);
+		}
+		lastResponse = await page
+			.evaluate(
+				async ({ methodName, methodParams }) => {
+					var appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
+					if (!appScript) throw new Error("app module script not found");
+					var appUrl = new URL(appScript.src, window.location.origin);
+					var prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
+					var helpers = await import(`${prefix}js/helpers.js`);
+					return helpers.sendRpc(methodName, methodParams);
+				},
+				{
+					methodName: method,
+					methodParams: params,
+				},
+			)
+			.catch((error) => ({ ok: false, error: { message: error?.message || String(error) } }));
+
+		if (lastResponse?.ok) return lastResponse;
+		if (!isRetryableRpcError(lastResponse?.error?.message)) return lastResponse;
+	}
+	return lastResponse;
+}
+
+async function expectRpcOk(page, method, params) {
+	const response = await sendRpcFromPage(page, method, params);
+	expect(response?.ok, `RPC ${method} failed: ${response?.error?.message || "unknown error"}`).toBeTruthy();
+	return response;
+}
+
+test.describe("API-sent user messages (GH #729)", () => {
+	test.beforeEach(async ({ page }) => {
+		await navigateAndWait(page, "/chats/main");
+		await waitForWsConnected(page);
+
+		// Wait for session switch to finish so renderHistory() doesn't
+		// clear injected DOM elements.
+		await page.waitForFunction(
+			async () => {
+				var appScript = document.querySelector('script[type="module"][src*="js/app.js"]');
+				if (!appScript) return false;
+				var appUrl = new URL(appScript.src, window.location.origin);
+				var prefix = appUrl.href.slice(0, appUrl.href.length - "js/app.js".length);
+				var state = await import(`${prefix}js/state.js`);
+				return !(state.sessionSwitchInProgress || state.chatBatchLoading);
+			},
+			{ timeout: 10_000 },
+		);
+	});","html_url":"https://github.com/moltis-org/moltis/pull/734#discussion_r3089333037","id":3089333037,"line":78,"node_id":"PRRC_kwDOREW6tc64I3st","original_commit_id":"8fb4d75e73307ea7290e115f9ba4014753c60c5c","original_line":78,"original_position":78,"original_start_line":61,"path":"crates/web/ui/e2e/specs/chat-api-message.spec.js","position":78,"pull_request_review_id":4116778662,"pull_request_url":"https://api.github.com/repos/moltis-org/moltis/pulls/734","reactions":{"+1":0,"-1":0,"confused":0,"eyes":0,"heart":0,"hooray":0,"laugh":0,"rocket":0,"total_count":0,"url":"https://api.github.com/repos/moltis-org/moltis/pulls/comments/3089333037/reactions"},"side":"RIGHT","start_line":61,"start_side":"RIGHT","subject_type":"line","updated_at":"2026-04-15T20:59:52Z","url":"https://api.github.com/repos/moltis-org/moltis/pulls/comments/3089333037","user":{"avatar_url":"https://avatars.githubusercontent.com/in/867647?v=4","events_url":"https://api.github.com/users/greptile-apps%5Bbot%5D/events{/privacy}","followers_url":"https://api.github.com/users/greptile-apps%5Bbot%5D/followers","following_url":"https://api.github.com/users/greptile-apps%5Bbot%5D/following{/other_user}","gists_url":"https://api.github.com/users/greptile-apps%5Bbot%5D/gists{/gist_id}","gravatar_id":"","html_url":"https://github.com/apps/greptile-apps","id":165735046,"login":"greptile-apps[bot]","node_id":"BOT_kgDOCeDqhg","organizations_url":"https://api.github.com/users/greptile-apps%5Bbot%5D/orgs","received_events_url":"https://api.github.com/users/greptile-apps%5Bbot%5D/received_events","repos_url":"https://api.github.com/users/greptile-apps%5Bbot%5D/repos","site_admin":false,"starred_url":"https://api.github.com/users/greptile-apps%5Bbot%5D/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/greptile-apps%5Bbot%5D/subscriptions","type":"Bot","url":"https://api.github.com/users/greptile-apps%5Bbot%5D","user_view_type":"public"}}]

